    val memo = mutable.Map[Long, Int]()

    def popcount(x: Long): Int = {
        var count = 0
        var num = x
        while (num > 0) {
            count += 1
            num = num & (num - 1)
        }
        count
    }

    def getDepth(x: Long): Int = {
        if (x == 1) return 0
        memo.getOrElseUpdate(x, {
            val next = popcount(x)
            1 + getDepth(next)
        })
    }

    (1L to n).count(x => getDepth(x) == k)
}
