    function popcount(x) {
        return x.toString(2).split('0').join('').length;
    }

    function getDepth(x) {
        let depth = 0;
        while (x !== 1) {
            x = popcount(x);
            depth++;
        }
        return depth;
    }

    let count = 0;
    for (let x = 1; x <= n; x++) {
